import{_ as e,o as t,c as d,a2 as o}from"./chunks/framework.C90q7Ucc.js";const h=JSON.parse('{"title":"运行时与提供方","description":"","frontmatter":{},"headers":[],"relativePath":"product/runtime-providers.md","filePath":"product/runtime-providers.md","lastUpdated":1781108296000}'),a={name:"product/runtime-providers.md"};function i(u,r,c,l,s,n){return t(),d("div",null,[...r[0]||(r[0]=[o('<h1 id="运行时与提供方" tabindex="-1">运行时与提供方 <a class="header-anchor" href="#运行时与提供方" aria-label="Permalink to &quot;运行时与提供方&quot;">​</a></h1><p>CodeLark 把“使用哪个 AI 工具”和“如何驱动它”拆成两层。</p><ul><li>运行时：当前会话使用 Codex 还是 Claude Code。</li><li>提供方：当前运行时通过 SDK、pty 或 tmux 运行。</li></ul><h2 id="能力矩阵" tabindex="-1">能力矩阵 <a class="header-anchor" href="#能力矩阵" aria-label="Permalink to &quot;能力矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>运行时</th><th>提供方</th><th>适用场景</th><th>输出路径</th></tr></thead><tbody><tr><td>Codex</td><td><code>sdk</code></td><td>结构化事件、工具调用、直接 IM turn</td><td>原生 SDK stream</td></tr><tr><td>Codex</td><td><code>pty</code></td><td>复用 Codex TUI 行为，观察真实终端</td><td>JSONL mirror + pty screen</td></tr><tr><td>Codex</td><td><code>tmux</code></td><td>需要可 attach 的长会话</td><td>tmux screen + JSONL mirror</td></tr><tr><td>Claude Code</td><td><code>tmux</code></td><td>默认路径；需要可 attach 的 Claude Code TUI 长会话</td><td>tmux screen + Claude JSONL mirror</td></tr><tr><td>Claude Code</td><td><code>pty</code></td><td>使用本机 <code>claude</code> 或 <code>ccr code</code> TUI</td><td>Claude JSONL mirror + pty screen</td></tr><tr><td>Claude Code</td><td><code>sdk</code></td><td>使用 Claude Agent SDK</td><td>SDK message stream</td></tr></tbody></table><p>补充说明：</p><ul><li>Claude Code 运行时默认使用 <code>tmux</code> 提供方，便于从 IM 和本机终端同时观察/接管 Claude Code TUI；可通过 <code>/provider pty</code> 或 <code>/provider sdk</code> 为当前会话切换。</li><li>Codex 运行时的默认提供方由全局配置和平台探测共同决定；需要可 attach 的长期终端会话时，优先选择 <code>tmux</code>。</li></ul><h2 id="用户配置入口" tabindex="-1">用户配置入口 <a class="header-anchor" href="#用户配置入口" aria-label="Permalink to &quot;用户配置入口&quot;">​</a></h2><ul><li><code>/runtime codex|claude</code>：切换当前会话使用的运行时。</li><li><code>/provider</code> 或 <code>/p</code>：查看或切换当前运行时的提供方。</li><li><code>/model</code>：查看或切换当前会话模型。</li><li><code>/cd &lt;path&gt;</code>：修改当前会话工作目录。</li><li><code>/set</code>：查看或修改全局默认值。</li><li>Web 工作台配置页：编辑全局默认值。</li><li>Web 工作台会话配置弹窗：编辑单个会话的覆盖值。</li></ul><p>Claude 的 <code>executable</code> 影响 <code>tmux</code> 和 <code>pty</code> 提供方；Claude SDK 提供方不走本机 <code>claude</code> / <code>ccr code</code> TUI。</p><h2 id="设计模块" tabindex="-1">设计模块 <a class="header-anchor" href="#设计模块" aria-label="Permalink to &quot;设计模块&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主题</th><th>模块</th></tr></thead><tbody><tr><td>提供方路由</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/runtime/codex/routing-provider.ts" target="_blank" rel="noreferrer">src/runtime/codex/routing-provider.ts</a></td></tr><tr><td>Codex SDK</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/runtime/codex/provider.ts" target="_blank" rel="noreferrer">src/runtime/codex/provider.ts</a></td></tr><tr><td>Codex pty</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/runtime/codex/pty-provider.ts" target="_blank" rel="noreferrer">src/runtime/codex/pty-provider.ts</a></td></tr><tr><td>Codex tmux</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/runtime/codex/tmux-provider.ts" target="_blank" rel="noreferrer">src/runtime/codex/tmux-provider.ts</a></td></tr><tr><td>Claude tmux</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/runtime/claude/tmux-provider.ts" target="_blank" rel="noreferrer">src/runtime/claude/tmux-provider.ts</a></td></tr><tr><td>tmux session 生命周期</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/tmux/runtime.ts" target="_blank" rel="noreferrer">src/bridge/tmux/runtime.ts</a></td></tr><tr><td>Claude pty</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/runtime/claude/pty-provider.ts" target="_blank" rel="noreferrer">src/runtime/claude/pty-provider.ts</a></td></tr><tr><td>Claude SDK</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/runtime/claude/sdk-provider.ts" target="_blank" rel="noreferrer">src/runtime/claude/sdk-provider.ts</a></td></tr><tr><td>Claude Code Router</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/runtime/claude/code-router.ts" target="_blank" rel="noreferrer">src/runtime/claude/code-router.ts</a></td></tr><tr><td>会话运行时设置</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/domain/session-runtime.ts" target="_blank" rel="noreferrer">src/domain/session-runtime.ts</a></td></tr><tr><td>交互 turn</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/turn/interactive/runner.ts" target="_blank" rel="noreferrer">src/bridge/turn/interactive/runner.ts</a></td></tr></tbody></table><h2 id="镜像与-sdk-输出差异" tabindex="-1">镜像与 SDK 输出差异 <a class="header-anchor" href="#镜像与-sdk-输出差异" aria-label="Permalink to &quot;镜像与 SDK 输出差异&quot;">​</a></h2><p>SDK 提供方通常直接把结构化事件交给 IM turn。pty / tmux 提供方更接近真实终端使用，会依赖本地 JSONL mirror 把最终输出同步到 IM。</p><p>tmux Provider 的普通文本会先转发到 tmux 中的当前 runtime TUI。Codex tmux 如需自动预创建 <code>codex_thread_id</code> 或恢复缺失的 tmux session，启动进度会更新到同一张 Provider 卡片；Claude tmux 会启动或复用 Claude Code TUI，并通过 Claude JSONL mirror 同步输出。显式发送 <code>/p tmux</code> 时，Codex 和 Claude 都通过同一套 tmux runtime 生命周期入口创建或重建 provider-owned session，确保新的 TUI 启动参数生效。shared runtime 会在 ready 检测和屏幕查看时报告 Codex/Claude selection prompt；<code>/clear</code> 和 <code>/t archive</code> 会 best-effort 清理记录在 runtime state 中的 tmux provider session。输入成功转发后，原用户消息会短暂添加 <code>Typing</code> reaction，直到 mirror stream 启动并开始同步本地 JSONL 输出。</p><p>相关模块：</p><ul><li>mirror 订阅：<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/mirror/subscription-registry.ts" target="_blank" rel="noreferrer">src/bridge/mirror/subscription-registry.ts</a></li><li>mirror 运行时：<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/mirror/runtime.ts" target="_blank" rel="noreferrer">src/bridge/mirror/runtime.ts</a></li><li>mirror turn 合并：<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/mirror/turns.ts" target="_blank" rel="noreferrer">src/bridge/mirror/turns.ts</a></li><li>mirror 反馈：<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/mirror/feedback-controller.ts" target="_blank" rel="noreferrer">src/bridge/mirror/feedback-controller.ts</a></li></ul>',17)])])}const b=e(a,[["render",i]]);export{h as __pageData,b as default};
